        const item = newsItems[currentNewsIndex];

        // Special case for Book Release (id: 1)
        if (item.id === 1) {
            e.preventDefault();
            onNavigateToBookRelease();
            return;
        }

        // Special case for the Consultant Agreement news item (id: 2)
        if (item.id === 2) {
             e.preventDefault();
             onNavigateToAgreement();
             return;
        }

        // Special case for the Event Calendar news item (id: 3)
        if (item.id === 3) {
             e.preventDefault();
             onNavigateToCalendar();
             return;
        }

        // Special case for Membership Promo (id: 4)
        if (item.id === 4) {
            e.preventDefault();
            onNavigateToMembershipPromo();
            return;
        }

        // Om det är en intern länk (#), scrolla. Annars navigera.
        const href = item.href;
        if (href.startsWith('#')) {
            scrollToId(e, href.substring(1)); // Ta bort #
        } else {
            window.location.href = href;
        }
